module RefModule (CLK, RST, SI, Q);
input CLK, RST, SI;
output reg [7:0] Q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge RST or posedge dbg_halt) begin
    if (RST) begin
        Q <= 8'b00000000;
    end else begin
        Q <= {Q[6:0], SI};
    end
end

endmodule
